# Example: Simple load balancer implementation

import random
import time
from dataclasses import dataclass, field
from typing import List
from collections import defaultdict
from threading import Lock


@dataclass
class Server:
    id: str
    address: str
    port: int
    weight: int = 1
    active_connections: int = 0
    total_requests: int = 0
    avg_response_time: float = 0.0
    healthy: bool = True


@dataclass
class LoadBalancer:
    servers: List[Server] = field(default_factory=list)
    algorithm: str = "round_robin"
    _lock: Lock = field(default_factory=Lock)
    _round_robin_index: int = 0
    _connection_counts: defaultdict = field(default_factory=lambda: defaultdict(int))

    def add_server(self, server: Server):
        self.servers.append(server)

    def remove_server(self, server_id: str):
        self.servers = [s for s in self.servers if s.id != server_id]

    def get_server(self, client_ip: str = None) -> Server:
        """Select a server based on the configured algorithm."""
        healthy_servers = [s for s in self.servers if s.healthy]
        if not healthy_servers:
            raise Exception("No healthy servers available")

        with self._lock:
            if self.algorithm == "round_robin":
                return self._round_robin(healthy_servers)
            elif self.algorithm == "least_connections":
                return self._least_connections(healthy_servers)
            elif self.algorithm == "weighted_round_robin":
                return self._weighted_round_robin(healthy_servers)
            elif self.algorithm == "ip_hash":
                return self._ip_hash(healthy_servers, client_ip)
            elif self.algorithm == "least_response_time":
                return self._least_response_time(healthy_servers)
            else:
                return self._round_robin(healthy_servers)

    def _round_robin(self, servers: List[Server]) -> Server:
        server = servers[self._round_robin_index % len(servers)]
        self._round_robin_index += 1
        return server

    def _least_connections(self, servers: List[Server]) -> Server:
        return min(servers, key=lambda s: s.active_connections)

    def _weighted_round_robin(self, servers: List[Server]) -> Server:
        total_weight = sum(s.weight for s in servers)
        self._round_robin_index = (self._round_robin_index + 1) % total_weight
        cumulative = 0
        for server in servers:
            cumulative += server.weight
            if self._round_robin_index < cumulative:
                return server
        return servers[-1]

    def _ip_hash(self, servers: List[Server], client_ip: str) -> Server:
        if not client_ip:
            return self._round_robin(servers)
        hash_value = hash(client_ip) % len(servers)
        return servers[hash_value]

    def _least_response_time(self, servers: List[Server]) -> Server:
        return min(servers, key=lambda s: s.avg_response_time)

    def health_check(self):
        """Perform health checks on all servers."""
        for server in self.servers:
            try:
                # Simulate health check
                start = time.time()
                # In real implementation, make HTTP request
                healthy = True
                server.healthy = healthy
                server.avg_response_time = (time.time() - start) * 1000
            except Exception:
                server.healthy = False


# Example usage
lb = LoadBalancer(algorithm="least_connections")

# Add servers
for i in range(4):
    lb.add_server(Server(
        id=f"server-{i}",
        address=f"10.0.0.{i+1}",
        port=8080,
        weight=i + 1
    ))

# Simulate requests
print("Load Balancer Algorithm Comparison:")
print("-" * 50)

for algo in ["round_robin", "least_connections", "weighted_round_robin"]:
    lb.algorithm = algo
    lb._round_robin_index = 0
    distribution = defaultdict(int)

    for _ in range(100):
        try:
            server = lb.get_server(client_ip=f"192.168.1.{random.randint(1, 255)}")
            distribution[server.id] += 1
        except Exception as e:
            print(f"Error: {e}")

    print(f"\n{algo}:")
    for server_id, count in sorted(distribution.items()):
        print(f"  {server_id}: {count} requests")
